def rotate_buffer(buffer, k):
    if not buffer:
        return []
    k = k % len(buffer)
    if k == 0:
        return buffer[:]
    return buffer[-k:] + buffer[:-k]

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic_rotation(self):
        self.assertEqual(rotate_buffer([1, 2, 3, 4, 5], 2), [4, 5, 1, 2, 3])

    def test_rotate_by_one(self):
        self.assertEqual(rotate_buffer([10, 20, 30], 1), [30, 10, 20])

    def test_rotate_full_length(self):
        self.assertEqual(rotate_buffer([1, 2, 3, 4], 4), [1, 2, 3, 4])

    def test_hidden_empty_buffer(self):
        self.assertEqual(rotate_buffer([], 3), [])

    def test_hidden_single_element(self):
        self.assertEqual(rotate_buffer([42], 5), [42])

    def test_hidden_rotate_by_zero(self):
        self.assertEqual(rotate_buffer([1, 2, 3], 0), [1, 2, 3])

    def test_hidden_k_larger_than_length(self):
        self.assertEqual(rotate_buffer([1, 2, 3, 4, 5], 7), [4, 5, 1, 2, 3])

    def test_hidden_two_elements(self):
        self.assertEqual(rotate_buffer([1, 2], 1), [2, 1])

    def test_hidden_no_mutation(self):
        original = [1, 2, 3, 4, 5]
        result = rotate_buffer(original, 2)
        self.assertEqual(original, [1, 2, 3, 4, 5])
        self.assertEqual(result, [4, 5, 1, 2, 3])

if __name__ == '__main__':
    unittest.main()
